TITLE = '高額療養費計算【無料】年間医療費・自己負担額をシミュレーション'
DESCRIPTION = '高額療養費計算を完全無料でお使いいただけます。登録不要・スマートフォン対応のWebツールです。'
JS_CODE = '// State\n    const answers = {};\n    let currentStep = 1;\n    const totalSteps = 6;\n\n    // Select option\n    document.querySelectorAll(\'.quiz-option\').forEach(opt => {\n      opt.addEventListener(\'click\', function() {\n        const q = this.dataset.q;\n        document.querySelectorAll(`[data-q="${q}"]`).forEach(o => o.classList.remove(\'selected\'));\n        this.classList.add(\'selected\');\n        answers[`q${q}`] = this.dataset.v;\n        updateNextButton();\n      });\n    });\n\n    function updateNextButton() {\n      const btn = document.getElementById(\'btn-next\');\n      if (answers[`q${currentStep}`]) {\n        btn.disabled = false;\n        btn.classList.remove(\'opacity-50\', \'cursor-not-allowed\');\n        btn.classList.add(\'cursor-pointer\');\n        if (currentStep === totalSteps) {\n          btn.textContent = \'診断結果を見る 🎯\';\n          btn.classList.add(\'bg-green-600\');\n          btn.classList.remove(\'bg-blue-700\');\n        }\n      } else {\n        btn.disabled = true;\n        btn.classList.add(\'opacity-50\', \'cursor-not-allowed\');\n        btn.classList.remove(\'cursor-pointer\');\n      }\n    }\n\n    function updateProgress() {\n      const pct = Math.round((currentStep - 1) / totalSteps * 100);\n      document.getElementById(\'progress-bar\').style.width = pct + \'%\';\n      document.getElementById(\'progress-label\').textContent = `質問 ${currentStep} / ${totalSteps}`;\n      document.getElementById(\'progress-pct\').textContent = pct + \'%\';\n    }\n\n    function goNext() {\n      if (!answers[`q${currentStep}`]) return;\n      if (currentStep === totalSteps) {\n        showResult();\n        return;\n      }\n      document.getElementById(`step-${currentStep}`).classList.add(\'hidden\');\n      currentStep++;\n      document.getElementById(`step-${currentStep}`).classList.remove(\'hidden\');\n      document.getElementById(\'btn-back\').classList.remove(\'hidden\');\n      updateNextButton();\n      updateProgress();\n    }\n\n    function goBack() {\n      if (currentStep <= 1) return;\n      document.getElementById(`step-${currentStep}`).classList.add(\'hidden\');\n      currentStep--;\n      document.getElementById(`step-${currentStep}`).classList.remove(\'hidden\');\n      if (currentStep === 1) document.getElementById(\'btn-back\').classList.add(\'hidden\');\n      updateNextButton();\n      updateProgress();\n    }\n\n    function calcResult() {\n      const q1 = answers.q1; // age\n      const q2 = answers.q2; // family\n      const q3 = answers.q3; // health\n      const q4 = answers.q4; // insurance\n      const q5 = answers.q5; // past\n      const q6 = answers.q6; // concern\n\n      // Base by age\n      const ageBase = { \'20\': 50000, \'30\': 80000, \'40\': 130000, \'50\': 200000, \'60\': 350000 };\n      let base = ageBase[q1] || 100000;\n\n      // Health multiplier\n      const healthMult = { \'very_healthy\': 0.5, \'healthy\': 1.0, \'chronic\': 2.5, \'hospitalized\': 5.0 };\n      base *= (healthMult[q3] || 1.0);\n\n      // Family addition\n      const familyAdd = { \'single\': 0, \'couple\': 60000, \'kids_young\': 80000, \'kids_older\': 50000, \'care\': 200000 };\n      base += (familyAdd[q2] || 0);\n\n      // Past adjustment\n      const pastMap = { \'almost_zero\': 0.8, \'low\': 1.0, \'mid\': 1.3, \'high\': 1.8 };\n      base *= (pastMap[q5] || 1.0);\n\n      const low = Math.round(base * 0.7 / 10000) * 10000;\n      const high = Math.round(base * 1.4 / 10000) * 10000;\n      const mid = Math.round(base / 10000) * 10000;\n\n      // Risk level\n      let risk, riskColor;\n      if (base < 100000) { risk = \'低リスク\'; riskColor = \'bg-green-500\'; }\n      else if (base < 300000) { risk = \'中リスク\'; riskColor = \'bg-yellow-400\'; }\n      else { risk = \'高リスク\'; riskColor = \'bg-red-500\'; }\n\n      // Advice\n      const advices = [];\n      if (q3 === \'very_healthy\' || q3 === \'healthy\') {\n        advices.push({ icon: \'✅\', text: \'健康状態が良好です。今後の備えとして貯蓄型の医療保険や医療費積立も検討しましょう。\' });\n      }\n      if (q3 === \'chronic\' || q3 === \'hospitalized\') {\n        advices.push({ icon: \'⚠️\', text: \'持病・入院歴がある場合、高額療養費制度の「限度額適用認定証」を事前に取得しておくと窓口での支払いを大幅に抑えられます。\' });\n     '
